import React from 'react';
import { BrowserRouter, Route } from "react-router-dom";
import './App.css';
import Home from './Components/Home/Home';

function App() {
  return (
    <BrowserRouter>
      <div className="App">
        <Route path="/" exact component={Home} />
        <Route path="/about" exact render={() => {<div>Sobre Mi</div>}} />
        <Route path="/portfolio" exact render={() => {<div>Proyectos</div>}} />
        <Route path="/contact" exact render={() => {<div>Contacto</div>}} />
      </div>
    </BrowserRouter>

  );
}

export default App;
